import{_ as s,c as i,o as l,a1 as o}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Journal des Versions : Mises à Jour | OpenSkills","description":"Consultez l'historique des versions d'OpenSkills, découvrez les nouvelles fonctionnalités comme la commande update, les liens symboliques, les dépôts privés, ainsi que les améliorations importantes et les corrections de bugs.","frontmatter":{"title":"Journal des Versions : Mises à Jour | OpenSkills","sidebarTitle":"Voir les Nouveautés","subtitle":"Journal des Versions : Mises à Jour | OpenSkills","description":"Consultez l'historique des versions d'OpenSkills, découvrez les nouvelles fonctionnalités comme la commande update, les liens symboliques, les dépôts privés, ainsi que les améliorations importantes et les corrections de bugs.","tags":["journal","historique des versions"],"order":1},"headers":[],"relativePath":"fr/numman-ali/openskills/changelog/changelog/index.md","filePath":"fr/numman-ali/openskills/changelog/changelog/index.md"}`),a={name:"fr/numman-ali/openskills/changelog/changelog/index.md"};function n(t,e,r,d,c,u){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="journal-des-versions" tabindex="-1">Journal des Versions <a class="header-anchor" href="#journal-des-versions" aria-label="Permalink to &quot;Journal des Versions&quot;">​</a></h1><p>Cette page enregistre l&#39;historique des versions d&#39;OpenSkills pour vous aider à comprendre les nouvelles fonctionnalités, les améliorations et les corrections de bugs de chaque version.</p><hr><h2 id="_1-5-0-2026-01-17" tabindex="-1">[1.5.0] - 2026-01-17 <a class="header-anchor" href="#_1-5-0-2026-01-17" aria-label="Permalink to &quot;[1.5.0] - 2026-01-17&quot;">​</a></h2><h3 id="nouvelles-fonctionnalites" tabindex="-1">Nouvelles Fonctionnalités <a class="header-anchor" href="#nouvelles-fonctionnalites" aria-label="Permalink to &quot;Nouvelles Fonctionnalités&quot;">​</a></h3><ul><li><strong><code>openskills update</code></strong> - Rafraîchit les compétences installées à partir des sources enregistrées (par défaut : tout rafraîchir)</li><li><strong>Suivi des métadonnées source</strong> - L&#39;installation enregistre désormais les informations de source pour des mises à jour fiables des compétences</li></ul><h3 id="ameliorations" tabindex="-1">Améliorations <a class="header-anchor" href="#ameliorations" aria-label="Permalink to &quot;Améliorations&quot;">​</a></h3><ul><li><strong>Lecture multi-compétences</strong> - La commande <code>openskills read</code> prend désormais en charge une liste de noms de compétences séparés par des virgules</li><li><strong>Instructions d&#39;utilisation générées</strong> - Optimisation des suggestions d&#39;appel de la commande read dans les environnements shell</li><li><strong>README</strong> - Ajout du guide de mise à jour et des conseils pour une utilisation manuelle</li></ul><h3 id="corrections-de-bugs" tabindex="-1">Corrections de Bugs <a class="header-anchor" href="#corrections-de-bugs" aria-label="Permalink to &quot;Corrections de Bugs&quot;">​</a></h3><ul><li><strong>Optimisation de l&#39;expérience de mise à jour</strong> - Ignore les compétences sans métadonnées de source et liste ces compétences pour une réinstallation</li></ul><hr><h2 id="_1-4-0-2026-01-17" tabindex="-1">[1.4.0] - 2026-01-17 <a class="header-anchor" href="#_1-4-0-2026-01-17" aria-label="Permalink to &quot;[1.4.0] - 2026-01-17&quot;">​</a></h2><h3 id="ameliorations-1" tabindex="-1">Améliorations <a class="header-anchor" href="#ameliorations-1" aria-label="Permalink to &quot;Améliorations&quot;">​</a></h3><ul><li><strong>README</strong> - Clarification de la méthode d&#39;installation locale par défaut du projet et suppression des suggestions sync redondantes</li><li><strong>Messages d&#39;installation</strong> - L&#39;installateur distingue désormais clairement l&#39;installation locale par défaut du projet et l&#39;option <code>--global</code></li></ul><hr><h2 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h2><h3 id="ameliorations-2" tabindex="-1">Améliorations <a class="header-anchor" href="#ameliorations-2" aria-label="Permalink to &quot;Améliorations&quot;">​</a></h3><ul><li><strong>Documentation et directives AGENTS.md</strong> - Tous les exemples de commandes et les instructions d&#39;utilisation générées utilisent désormais uniformément <code>npx openskills</code></li></ul><hr><h2 id="_1-3-1-2026-01-17" tabindex="-1">[1.3.1] - 2026-01-17 <a class="header-anchor" href="#_1-3-1-2026-01-17" aria-label="Permalink to &quot;[1.3.1] - 2026-01-17&quot;">​</a></h2><h3 id="corrections-de-bugs-1" tabindex="-1">Corrections de Bugs <a class="header-anchor" href="#corrections-de-bugs-1" aria-label="Permalink to &quot;Corrections de Bugs&quot;">​</a></h3><ul><li><strong>Installation Windows</strong> - Correction du problème de validation de chemin sur les systèmes Windows (&quot;Erreur de sécurité : chemin d&#39;installation en dehors du répertoire cible&quot;)</li><li><strong>Version CLI</strong> - <code>npx openskills --version</code> lit désormais correctement le numéro de version dans package.json</li><li><strong>SKILL.md à la racine</strong> - Correction du problème d&#39;installation SKILL.md dans le répertoire racine des dépôts à compétence unique</li></ul><hr><h2 id="_1-3-0-2025-12-14" tabindex="-1">[1.3.0] - 2025-12-14 <a class="header-anchor" href="#_1-3-0-2025-12-14" aria-label="Permalink to &quot;[1.3.0] - 2025-12-14&quot;">​</a></h2><h3 id="nouvelles-fonctionnalites-1" tabindex="-1">Nouvelles Fonctionnalités <a class="header-anchor" href="#nouvelles-fonctionnalites-1" aria-label="Permalink to &quot;Nouvelles Fonctionnalités&quot;">​</a></h3><ul><li><p><strong>Prise en charge des liens symboliques</strong> - Les compétences peuvent désormais être installées via des liens symboliques vers le répertoire des compétences (<a href="https://github.com/numman-ali/openskills/issues/3" target="_blank" rel="noreferrer">#3</a>)</p><ul><li>Prise en charge des mises à jour de compétences basées sur git via la création de liens symboliques à partir de dépôts clonés</li><li>Prise en charge du flux de travail de développement local de compétences</li><li>Les liens symboliques rompus sont ignorés gracieusement</li></ul></li><li><p><strong>Chemin de sortie configurable</strong> - La commande sync prend désormais en charge les options <code>--output</code> / <code>-o</code> (<a href="https://github.com/numman-ali/openskills/issues/5" target="_blank" rel="noreferrer">#5</a>)</p><ul><li>Peut se synchroniser vers n&#39;importe quel fichier <code>.md</code> (par exemple <code>.ruler/AGENTS.md</code>)</li><li>Crée automatiquement le fichier et ajoute le titre si le fichier n&#39;existe pas</li><li>Crée automatiquement les répertoires imbriqués si nécessaire</li></ul></li><li><p><strong>Installation par chemin local</strong> - Prise en charge de l&#39;installation de compétences à partir de répertoires locaux (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>Prise en charge des chemins absolus (<code>/path/to/skill</code>)</li><li>Prise en charge des chemins relatifs (<code>./skill</code>, <code>../skill</code>)</li><li>Prise en charge de l&#39;expansion tilde (<code>~/my-skills/skill</code>)</li></ul></li><li><p><strong>Prise en charge des dépôts git privés</strong> - Prise en charge de l&#39;installation de compétences à partir de dépôts privés (<a href="https://github.com/numman-ali/openskills/issues/10" target="_blank" rel="noreferrer">#10</a>)</p><ul><li>URLs SSH (<code>git@github.com:org/private-skills.git</code>)</li><li>URLs HTTPS avec authentification</li><li>Utilisation automatique des clés SSH système</li></ul></li><li><p><strong>Suite de tests complète</strong> - 88 tests dans 6 fichiers de test</p><ul><li>Tests unitaires pour la détection des liens symboliques, l&#39;analyse YAML</li><li>Tests d&#39;intégration pour les commandes install, sync</li><li>Tests de bout en bout pour le flux de travail CLI complet</li></ul></li></ul><h3 id="ameliorations-3" tabindex="-1">Améliorations <a class="header-anchor" href="#ameliorations-3" aria-label="Permalink to &quot;Améliorations&quot;">​</a></h3><ul><li><p><strong><code>--yes</code> flag saute maintenant toutes les invites</strong> - Mode entièrement non interactif, adapté pour CI/CD (<a href="https://github.com/numman-ali/openskills/issues/6" target="_blank" rel="noreferrer">#6</a>)</p><ul><li>Ne demande pas lors du remplacement de compétences existantes</li><li>Affiche le message <code>Overwriting: &lt;skill-name&gt;</code> lors du saut des invites</li><li>Toutes les commandes peuvent désormais s&#39;exécuter dans des environnements headless</li></ul></li><li><p><strong>Réorganisation du workflow CI</strong> - L&#39;étape de build s&#39;exécute désormais avant les tests</p><ul><li>Assure que <code>dist/cli.js</code> existe pour les tests de bout en bout</li></ul></li></ul><h3 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h3><ul><li><strong>Protection contre la traversée de chemin</strong> - Validation que les chemins d&#39;installation restent dans le répertoire cible</li><li><strong>Déréférencement des liens symboliques</strong> - <code>cpSync</code> utilise <code>dereference: true</code> pour copier en toute sécurité les cibles des liens symboliques</li><li><strong>Regex YAML non-gourmand</strong> - Prévention des attaques ReDoS potentielles dans l&#39;analyse frontmatter</li></ul><hr><h2 id="_1-2-1-2025-10-27" tabindex="-1">[1.2.1] - 2025-10-27 <a class="header-anchor" href="#_1-2-1-2025-10-27" aria-label="Permalink to &quot;[1.2.1] - 2025-10-27&quot;">​</a></h2><h3 id="corrections-de-bugs-2" tabindex="-1">Corrections de Bugs <a class="header-anchor" href="#corrections-de-bugs-2" aria-label="Permalink to &quot;Corrections de Bugs&quot;">​</a></h3><ul><li>Nettoyage de la documentation README - Suppression des sections dupliquées et des drapeaux incorrects</li></ul><hr><h2 id="_1-2-0-2025-10-27" tabindex="-1">[1.2.0] - 2025-10-27 <a class="header-anchor" href="#_1-2-0-2025-10-27" aria-label="Permalink to &quot;[1.2.0] - 2025-10-27&quot;">​</a></h2><h3 id="nouvelles-fonctionnalites-2" tabindex="-1">Nouvelles Fonctionnalités <a class="header-anchor" href="#nouvelles-fonctionnalites-2" aria-label="Permalink to &quot;Nouvelles Fonctionnalités&quot;">​</a></h3><ul><li>Drapeau <code>--universal</code>, installe les compétences dans <code>.agent/skills/</code> au lieu de <code>.claude/skills/</code><ul><li>Adapté aux environnements multi-agents (Claude Code + Cursor/Windsurf/Aider)</li><li>Évite les conflits avec les plugins du marché natif Claude Code</li></ul></li></ul><h3 id="ameliorations-4" tabindex="-1">Améliorations <a class="header-anchor" href="#ameliorations-4" aria-label="Permalink to &quot;Améliorations&quot;">​</a></h3><ul><li>L&#39;installation locale du projet est désormais l&#39;option par défaut (auparavant c&#39;était l&#39;installation globale)</li><li>Les compétences sont installées par défaut dans <code>./.claude/skills/</code></li></ul><hr><h2 id="_1-1-0-2025-10-27" tabindex="-1">[1.1.0] - 2025-10-27 <a class="header-anchor" href="#_1-1-0-2025-10-27" aria-label="Permalink to &quot;[1.1.0] - 2025-10-27&quot;">​</a></h2><h3 id="nouvelles-fonctionnalites-3" tabindex="-1">Nouvelles Fonctionnalités <a class="header-anchor" href="#nouvelles-fonctionnalites-3" aria-label="Permalink to &quot;Nouvelles Fonctionnalités&quot;">​</a></h3><ul><li>README complet sur une page, avec une analyse technique approfondie</li><li>Comparaison côte à côte avec Claude Code</li></ul><h3 id="corrections-de-bugs-3" tabindex="-1">Corrections de Bugs <a class="header-anchor" href="#corrections-de-bugs-3" aria-label="Permalink to &quot;Corrections de Bugs&quot;">​</a></h3><ul><li>Les étiquettes d&#39;emplacement affichent désormais correctement <code>project</code> ou <code>global</code> en fonction de l&#39;emplacement d&#39;installation</li></ul><hr><h2 id="_1-0-0-2025-10-26" tabindex="-1">[1.0.0] - 2025-10-26 <a class="header-anchor" href="#_1-0-0-2025-10-26" aria-label="Permalink to &quot;[1.0.0] - 2025-10-26&quot;">​</a></h2><h3 id="nouvelles-fonctionnalites-4" tabindex="-1">Nouvelles Fonctionnalités <a class="header-anchor" href="#nouvelles-fonctionnalites-4" aria-label="Permalink to &quot;Nouvelles Fonctionnalités&quot;">​</a></h3><ul><li>Version initiale</li><li><code>npx openskills install &lt;source&gt;</code> - Installe des compétences à partir de dépôts GitHub</li><li><code>npx openskills sync</code> - Génère <code>&lt;available_skills&gt;</code> XML pour AGENTS.md</li><li><code>npx openskills list</code> - Affiche les compétences installées</li><li><code>npx openskills read &lt;name&gt;</code> - Charge le contenu de la compétence pour l&#39;agent</li><li><code>npx openskills manage</code> - Suppression interactive des compétences</li><li><code>npx openskills remove &lt;name&gt;</code> - Supprime la compétence spécifiée</li><li>Interface TUI interactive pour toutes les commandes</li><li>Prise en charge du format SKILL.md d&#39;Anthropic</li><li>Divulgation progressive (chargement des compétences à la demande)</li><li>Prise en charge des ressources empaquetées (references/, scripts/, assets/)</li></ul><hr><h2 id="annexe-reference-source" tabindex="-1">Annexe : Référence Source <a class="header-anchor" href="#annexe-reference-source" aria-label="Permalink to &quot;Annexe : Référence Source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th></tr></thead><tbody><tr><td>Journal des versions original</td><td><a href="https://github.com/numman-ali/openskills/blob/main/CHANGELOG.md" target="_blank" rel="noreferrer"><code>CHANGELOG.md</code></a></td></tr></tbody></table></details>',53)])])}const p=s(a,[["render",n]]);export{h as __pageData,p as default};
